#include <stdbool.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>
#include <omp.h>

#define fp float

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void
findK(long height,
	  knode *knodesD,
	  long knodes_elem,
	  record *recordsD,

	  long *currKnodeD,
	  long *offsetD,
	  int *keysD, 
	  record *ansD,
	  int count,
	  int order)
{
	// Parallelize over count (bid equivalent)
#pragma omp parallel for schedule(static)
	for (int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		int key = keysD[bid];

		for (int i = 0; i < height; i++) {
			// For thid in [0, order-1], simulate the local threads
			// We'll find the index thid for which keys[thid] <= key < keys[thid+1]
			int thid = -1;
			for (int t = 0; t < order; t++) {
				int k1 = knodesD[currKnode].keys[t];
				int k2 = knodesD[currKnode].keys[t+1];
				if (k1 <= key && key < k2) {
					thid = t;
					break;
				}
			}
			if (thid >= 0) {
				if (knodesD[offset].indices[thid] < knodes_elem) {
					offset = knodesD[offset].indices[thid];
				}
			}
			currKnode = offset;
		}

		// Now find the correct answer for ansD[bid]
		int found_index = -1;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == key) {
				found_index = thid;
				break;
			}
		}
		if (found_index >= 0) {
			long record_index = knodesD[currKnode].indices[found_index];
			ansD[bid].value = recordsD[record_index].value;
		} else {
			ansD[bid].value = -1;
		}
	}
}

