#include <stdbool.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>
#include <omp.h>

#define fp float

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER_2 + 1];
	int  keys [DEFAULT_ORDER_2 + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void
findRangeK(long height,
		   knode *knodesD,
		   long knodes_elem,

		   long *currKnodeD,
		   long *offsetD,
		   long *lastKnodeD,
		   long *offset_2D,
		   int *startD,
		   int *endD,
		   int *RecstartD, 
		   int *ReclenD,
		   int count,
		   int order)
{
	// Parallelize over count (bid equivalent)
#pragma omp parallel for schedule(static)
	for (int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		long lastKnode = lastKnodeD[bid];
		long offset_2 = offset_2D[bid];
		int start = startD[bid];
		int end = endD[bid];

		for (int i = 0; i < height; i++) {
			// For thid in [0, order-1], simulate the local threads
			for (int thid = 0; thid < order; thid++) {
				if ((knodesD[currKnode].keys[thid] <= start) && (knodesD[currKnode].keys[thid+1] > start)) {
					if (knodesD[currKnode].indices[thid] < knodes_elem) {
						offset = knodesD[currKnode].indices[thid];
					}
				}
				if ((knodesD[lastKnode].keys[thid] <= end) && (knodesD[lastKnode].keys[thid+1] > end)) {
					if (knodesD[lastKnode].indices[thid] < knodes_elem) {
						offset_2 = knodesD[lastKnode].indices[thid];
					}
				}
			}
			currKnode = offset;
			lastKnode = offset_2;
		}

		currKnodeD[bid] = currKnode;
		offsetD[bid] = offset;
		lastKnodeD[bid] = lastKnode;
		offset_2D[bid] = offset_2;

		// Find RecstartD[bid]
		int recstart = 0;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == start) {
				recstart = knodesD[currKnode].indices[thid];
				break;
			}
		}
		RecstartD[bid] = recstart;

		// Find ReclenD[bid]
		int reclen = 0;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[lastKnode].keys[thid] == end) {
				reclen = knodesD[lastKnode].indices[thid] - recstart + 1;
				break;
			}
		}
		ReclenD[bid] = reclen;
	}
}
